'use strict';

// ----------------------------
// Dados (simulação)
// ----------------------------
const itens = [
  { id: 1, nome: 'Café' },
  { id: 2, nome: 'Leite' },
  { id: 3, nome: 'Pão' },
  { id: 4, nome: 'Bolo de cenoura' },
];

// ----------------------------
// Helpers DOM
// ----------------------------
function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) throw new Error(`Elemento não encontrado: ${sel}`);
  return el;
}

const elQ = assertEl('#q');
const elInfo = assertEl('#info');
const elLista = assertEl('#lista');
const elDetalhe = assertEl('#detalhe');

// ----------------------------
// Estado (fonte de verdade)
// ----------------------------
let state = {
  q: '',
  selectedId: null,
};

// ----------------------------
// Seletores derivados (puro)
// ----------------------------
function selectListaFiltrada(st) {
  const qn = String(st.q ?? '').trim().toLowerCase();
  if (!qn) return itens;
  return itens.filter((it) => it.nome.toLowerCase().includes(qn));
}

function selectSelecionado(st) {
  if (st.selectedId === null) return null;
  return itens.find((it) => it.id === st.selectedId) ?? null;
}

// ----------------------------
// Render (único lugar que escreve no DOM)
// ----------------------------
function render() {
  const lista = selectListaFiltrada(state);
  const sel = selectSelecionado(state);

  elInfo.textContent = `Total: ${lista.length}`;

  // Render lista
  elLista.innerHTML = '';
  for (const it of lista) {
    const li = document.createElement('li');
    li.textContent = it.nome;
    li.setAttribute('data-id', String(it.id));

    if (it.id === state.selectedId) {
      li.style.fontWeight = '700';
    }

    elLista.appendChild(li);
  }

  // Render detalhe
  elDetalhe.textContent = sel ? `#${sel.id} — ${sel.nome}` : 'Nenhum selecionado';
}

// ----------------------------
// Actions (mudam state e chamam render)
// ----------------------------
function setQuery(q) {
  state = { ...state, q: String(q ?? '') };
  // se o item selecionado saiu do filtro, opcionalmente deselecione
  const lista = selectListaFiltrada(state);
  const stillVisible = lista.some((it) => it.id === state.selectedId);
  if (!stillVisible) state = { ...state, selectedId: null };
  render();
}

function selectById(id) {
  const n = Number(id);
  if (!Number.isFinite(n)) return;
  state = { ...state, selectedId: n };
  render();
}

// ----------------------------
// Wire (eventos)
// ----------------------------
function wire() {
  elQ.addEventListener('input', () => setQuery(elQ.value));

  // Delegação: 1 listener na lista
  elLista.addEventListener('click', (e) => {
    const li = e.target.closest('li');
    if (!li) return;
    selectById(li.getAttribute('data-id'));
  });
}

wire();
render();
console.log('[state/render] pronto');
